mapper.update:
UPDATE festival_review
SET
    is_deleted = 'Y',
    updated_at = SYSDATE
WHERE review_id = #{review_id}
  AND member_id = #{member_id}

mapper.select:
SELECT COUNT(*)
FROM review_report
WHERE review_id = #{review_id}
  AND member_id = #{member_id}

mapper.update:
UPDATE festival_review
SET report_count = NVL(report_count, 0) + 1
WHERE review_id = #{review_id}

mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rnum, res.* FROM ( SELECT fr.review_id, fr.content_id, fr.member_id, fr.rating, fr.content, fr.visit_date, NVL(fr.report_count, 0) AS report_count, fr.created_at, fr.updated_at, fr.is_deleted, m.nickname, fi.title AS festival_title FROM festival_review fr LEFT JOIN member m ON fr.member_id = m.member_id LEFT JOIN festival_info fi ON fr.content_id = fi.content_id
AND NVL(fr.report_count, 0) >= 1 AND NVL(fr.is_deleted, 'N') = 'N'
AND fr.is_deleted = 'Y'
AND fr.rating = #{rating}
AND ( fr.content LIKE '%' || #{keyword} || '%' OR m.nickname LIKE '%' || #{keyword} || '%' OR TO_CHAR(fr.content_id) LIKE '%' || #{keyword} || '%' OR fi.title LIKE '%' || #{keyword} || '%' )
ORDER BY fr.created_at DESC ) res WHERE ROWNUM <= #{endRow} ) WHERE rnum >= #{startRow}

mapper.update:
UPDATE festival_review
SET report_count = 0
WHERE review_id = #{review_id}
